INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Primero Básico', 'Emprendimiento para la Productividad', '1. Elabora su proyecto de vida considerando el emprendimiento como herramienta para mejorar la calidad de vida desde su entorno familiar, cultural y comunitario.', ARRAY['1.1. Reconoce los principios del emprendimiento.', '1.2. Describe los aspectos y características que influyen en su vida personal y familiar.', '1.3. Valora la cultura de su comunidad.']),
('Primero Básico', 'Emprendimiento para la Productividad', '2. Diferencia los principios tecnológicos con normas de calidad, seguridad, higiene y pertinencia en procesos de producción.', ARRAY['2.1. Reconoce procesos y técnicas de producción.', '2.2. Reconoce la importancia de la aplicación de las normas de calidad, seguridad e higiene en los procesos de producción.', '2.3. Identifica las prácticas que brinden solución a problemas y que a la vez contribuyan al cuidado del medioambiente.']),
('Primero Básico', 'Emprendimiento para la Productividad', '3. Valora la importancia de administrar los bienes y recursos financieros para el desarrollo familiar y comunitario.', ARRAY['3.1. Explica la importancia de administrar los bienes familiares.', '3.2. Cuantifica los bienes familiares y ejecuta presupuestos.', '3.3. Identifica la relación entre las ocupaciones y actividades económicas de una comunidad eminentemente productiva.']);
